"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[870],{98519:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>c,frontMatter:()=>o,metadata:()=>r,toc:()=>h});var a=n(74848),i=n(28453);const o={slug:"DefconQ x Databento Meetup - The Market Data Provider You Wish Always Existed",title:"DefconQ x Databento Meetup - The Market Data Provider You Wish Always Existed",authors:["alexander"],hide_table_of_contents:!0,tags:["kdb/q","DefconQ","Databento","Market Data","Big Data","Meetup"]},s=void 0,r={permalink:"/blog/DefconQ x Databento Meetup - The Market Data Provider You Wish Always Existed",source:"@site/blog/2026-06-01-DefconQ-meets-Databento/index.md",title:"DefconQ x Databento Meetup - The Market Data Provider You Wish Always Existed",description:"There Is No KDB Without Market Data",date:"2026-06-01T00:00:00.000Z",tags:[{label:"kdb/q",permalink:"/blog/tags/kdb-q"},{label:"DefconQ",permalink:"/blog/tags/defcon-q"},{label:"Databento",permalink:"/blog/tags/databento"},{label:"Market Data",permalink:"/blog/tags/market-data"},{label:"Big Data",permalink:"/blog/tags/big-data"},{label:"Meetup",permalink:"/blog/tags/meetup"}],readingTime:6.005,hasTruncateMarker:!0,authors:[{name:"Alexander Unterrainer",title:"DefconQ, KDB/Q Developer, Consultant",url:"https://github.com/AUnterrainer",imageURL:"/img/alex.jpeg",key:"alexander"}],frontMatter:{slug:"DefconQ x Databento Meetup - The Market Data Provider You Wish Always Existed",title:"DefconQ x Databento Meetup - The Market Data Provider You Wish Always Existed",authors:["alexander"],hide_table_of_contents:!0,tags:["kdb/q","DefconQ","Databento","Market Data","Big Data","Meetup"]},unlisted:!1,nextItem:{title:"The Weekly Q Rumble - Sharpen Your KDB/Q Skills, One Challenge at a Time",permalink:"/blog/The Weekly Q Rumble - Sharpen Your KDB/Q Skills, One Challenge at a Time"}},l={authorsImageUrls:[void 0]},h=[{value:"There Is No KDB Without Market Data",id:"there-is-no-kdb-without-market-data",level:2},{value:"Who Is Databento?",id:"who-is-databento",level:2},{value:"The Founders Behind It",id:"the-founders-behind-it",level:2},{value:"How We Got Here",id:"how-we-got-here",level:2},{value:"From Tutorial to Meetup",id:"from-tutorial-to-meetup",level:2},{value:"Why You Should Attend",id:"why-you-should-attend",level:2}];function d(e){const t={a:"a",br:"br",em:"em",h2:"h2",img:"img",li:"li",p:"p",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.h2,{id:"there-is-no-kdb-without-market-data",children:"There Is No KDB Without Market Data"}),"\n",(0,a.jsxs)(t.p,{children:["Let\u2019s be honest: there is ",(0,a.jsx)(t.strong,{children:"no KDB/Q"})," without market data."]}),"\n",(0,a.jsx)(t.p,{children:"You can build the cleanest tickerplant in the world, design elegant schemas, optimise queries until they scream, and architect the perfect stack, but without data flowing into it, it\u2019s all just a very expensive and slightly nerdy sculpture."}),"\n",(0,a.jsxs)(t.p,{children:["Market data is the ",(0,a.jsx)(t.em,{children:"lifeblood"})," of every serious KDB/Q system. It\u2019s where the story begins.\nAnd yet, for something so fundamental, getting access to market data as an individual developer has historically been ... painful."]}),"\n",(0,a.jsxs)(t.p,{children:["That\u2019s exactly why I\u2019m excited to announce that ",(0,a.jsx)(t.strong,{children:"DefconQ"})," and ",(0,a.jsx)(t.a,{href:"https://databento.com",children:(0,a.jsx)(t.strong,{children:"Databento"})})," are teaming up for an upcoming ",(0,a.jsx)(t.strong,{children:"Meetup in London"}),", a community event for quants, financial engineers, developers, and anyone working with market data who wants to see what happens when market data stops being a headache and starts becoming something you can actually work with."]}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.img,{alt:"DefconQ meets Databento",src:n(73778).A+"",width:"1402",height:"1122"})}),"\n",(0,a.jsx)(t.h2,{id:"who-is-databento",children:"Who Is Databento?"}),"\n",(0,a.jsx)(t.p,{children:"If you haven\u2019t come across Databento yet, chances are you will. Databento recently celebrated its third anniversary, and in a remarkably short time has established itself as one of the most exciting and fastest-growing players in the market data space. The company was built around one core idea: creating modern market data infrastructure capable of serving some of the world\u2019s leading trading firms while still remaining accessible to individual developers, researchers, startups, and smaller teams."}),"\n",(0,a.jsx)(t.p,{children:"And clearly, that vision resonated."}),"\n",(0,a.jsx)(t.p,{children:"Today, Databento serves more than 40,000 users and powers firms representing hundreds of billions in AUM, alongside products spanning fintech, AI, quantitative research, and trading infrastructure. What makes Databento particularly refreshing is that it genuinely feels like it was built by engineers who have personally suffered through the pain of traditional market data providers before."}),"\n",(0,a.jsx)(t.p,{children:"Because they have."}),"\n",(0,a.jsx)(t.p,{children:"Historically, market data has often felt like it was built for procurement teams, lawyers, and infrastructure departments first ... and developers somewhere near the bottom of the priority list. Complicated onboarding. Opaque pricing. Questionable APIs. Documentation that feels like it was written during the Cold War. Strange licensing restrictions. Integration projects that somehow become multi-week engineering exercises."}),"\n",(0,a.jsx)(t.p,{children:"Databento flipped that script."}),"\n",(0,a.jsx)(t.p,{children:"Their platform makes it possible to access historical and real-time market data through a clean, well-documented API, without the usual layers of friction many developers have simply accepted as \u201cpart of the process.\u201d Fast access. Transparent pricing. Modern tooling. Excellent documentation."}),"\n",(0,a.jsx)(t.p,{children:"It sounds simple, but anyone who has integrated market data providers before knows this is absolutely not a given."}),"\n",(0,a.jsx)(t.h2,{id:"the-founders-behind-it",children:"The Founders Behind It"}),"\n",(0,a.jsx)(t.p,{children:"Databento was founded by people who clearly understand both the technical and commercial realities of market data because they lived through them themselves while working inside the industry."}),"\n",(0,a.jsxs)(t.p,{children:["At the top is ",(0,a.jsx)(t.a,{href:"https://www.linkedin.com/in/christinaqi/",children:"Christina Qi"}),", alongside ",(0,a.jsx)(t.a,{href:"https://www.linkedin.com/in/linl/",children:"Luca Lin"})," and ",(0,a.jsx)(t.a,{href:"https://www.linkedin.com/in/renan-gemignani/",children:"Renan Gemignani"}),". Together with the broader core team, they bring experience from prestigious hedge funds, quantitative trading firms, and high-performance financial infrastructure environments where market data is not just important, it is mission critical."]}),"\n",(0,a.jsx)(t.p,{children:"And honestly, I think that experience is exactly why the product feels different."}),"\n",(0,a.jsx)(t.p,{children:"This wasn\u2019t built by people theorising about market data problems from the outside. It was built by engineers and quants who were tired of dealing with bad market data vendors themselves. The frustrations that many of us have simply learned to tolerate, painful integrations, poor tooling, strange workflows, slow onboarding, became the motivation for building something better."}),"\n",(0,a.jsx)(t.p,{children:"And perhaps that\u2019s what stood out to me most when I met Christina and the Databento team in London: they genuinely understand the problems developers and engineers face because they\u2019ve been on the receiving end of them."}),"\n",(0,a.jsx)(t.p,{children:"That combination of technical depth, practical thinking, and building from real-world frustration tends to produce very good products."}),"\n",(0,a.jsx)(t.h2,{id:"how-we-got-here",children:"How We Got Here"}),"\n",(0,a.jsx)(t.p,{children:"This meetup actually started with a DefconQ tutorial. A while ago, I wrote my real-time stock market tutorial, walking readers through how to stream live data into a KDB/Q stack. Initially, I used Yahoo Finance to pull market data because, well ... it was free and it worked. Until it didn't."}),"\n",(0,a.jsx)(t.p,{children:"Anyone who has ever used Yahoo Finance for anything even remotely serious knows what happens next: you request a little too much data and suddenly the door gets slammed shut. That was a problem. I wanted to create something realistic for DefconQ readers, something that actually resembled how a production-style system works. But I also wasn\u2019t exactly sitting on a Bloomberg budget to pay for a full real-time market data feed just to support a tutorial."}),"\n",(0,a.jsx)(t.p,{children:"That\u2019s when I came across Databento. The free credits they provide were exactly what I needed to make the tutorial happen."}),"\n",(0,a.jsx)(t.p,{children:"Now, I\u2019ll be honest: my expectations were cautiously optimistic."}),"\n",(0,a.jsx)(t.p,{children:"Because integrating market data providers can be painful. Documentation gaps, weird APIs, unexpected licensing complexity, strange authentication workflows, if you\u2019ve done it before, you know."}),"\n",(0,a.jsx)(t.p,{children:"So I mentally blocked off some time for \u201cintegration pain.\u201d And then something strange happened: There wasn\u2019t any."}),"\n",(0,a.jsx)(t.p,{children:"Thanks to the excellent documentation and a genuinely easy-to-use API, I managed to integrate Databento into the tutorial in a single evening, while my wife was at a Beyonc\xe9 concert."}),"\n",(0,a.jsx)(t.p,{children:"That might sound like a silly benchmark, but trust me: in market data integration time, that\u2019s lightning fast."}),"\n",(0,a.jsx)(t.h2,{id:"from-tutorial-to-meetup",children:"From Tutorial to Meetup"}),"\n",(0,a.jsx)(t.p,{children:"The tutorial went on to become one of DefconQ\u2019s more popular hands-on walkthroughs, and to my surprise, Christina herself featured it. That eventually led to me meeting Christina and the Databento team at a London meetup, and if you\u2019ve ever wondered whether technical people can also be genuinely fun people, the answer is yes."}),"\n",(0,a.jsx)(t.p,{children:"Now they\u2019re back in town."}),"\n",(0,a.jsx)(t.p,{children:"And this time, we\u2019re hosting something together."}),"\n",(0,a.jsx)(t.h2,{id:"why-you-should-attend",children:"Why You Should Attend"}),"\n",(0,a.jsx)(t.p,{children:"This meetup is not just another fintech networking event where everyone pretends to enjoy warm white wine and vague conversations about \u201cinnovation.\u201d This is a real community event for people who actually work with data."}),"\n",(0,a.jsx)(t.p,{children:"If you are a:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"Quant"}),"\n",(0,a.jsx)(t.li,{children:"Financial Engineer"}),"\n",(0,a.jsx)(t.li,{children:"Market Data Engineer"}),"\n",(0,a.jsx)(t.li,{children:"KDB/Q Developer"}),"\n",(0,a.jsx)(t.li,{children:"or anyone building systems that depend on fast, reliable market data ..."}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"... this is genuinely worth attending."}),"\n",(0,a.jsx)(t.p,{children:"You\u2019ll get the opportunity to learn directly from the Databento team, understand how their platform works, ask technical questions, and see why accessing market data has become dramatically easier than it used to be."}),"\n",(0,a.jsx)(t.p,{children:"And perhaps just as importantly, you\u2019ll meet others in the DefconQ community who care about the same problems you do, architecture, infrastructure, data engineering, market data, production systems, and all the weird little things that only people in this niche get excited about."}),"\n",(0,a.jsx)(t.p,{children:"There will be conversations, technical discussions, networking, and plenty of opportunities to ask the questions you don\u2019t usually get to ask."}),"\n",(0,a.jsx)(t.p,{children:"Because at the end of the day, market data is where many of our systems begin."}),"\n",(0,a.jsx)(t.p,{children:"And if someone makes that easier for developers, it\u2019s worth paying attention."}),"\n",(0,a.jsx)(t.p,{children:"See you there."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"The Details"}),":"]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"When"}),": Wednesday, July 1st 2026 ",(0,a.jsx)(t.br,{}),"\n",(0,a.jsx)(t.strong,{children:"Where"}),": Hedosophia, 2 Soho Place, London W1D 3BG ",(0,a.jsx)(t.br,{}),"\n",(0,a.jsx)(t.strong,{children:"Sign Up Link"}),": ",(0,a.jsx)(t.a,{href:"https://luma.com/p22b7ff3",children:"here"})]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"IMPORTANT"}),": This event is expected to reach capacity, so sign up as soon as possible. If you can no longer attend, please cancel your registration to free up your spot for someone else."]}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.img,{alt:"DefconQ meets Databento",src:n(3128).A+"",width:"1536",height:"1024"})})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},73778:(e,t,n)=>{n.d(t,{A:()=>a});const a=n.p+"assets/images/DefconQDatabentoFusion-01f31f630e3ab88f51357632f4194174.png"},3128:(e,t,n)=>{n.d(t,{A:()=>a});const a=n.p+"assets/images/DefconQDatabentoMeetup-0c35425b38edc7b96fe26936bac2acd8.png"},28453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>r});var a=n(96540);const i={},o=a.createContext(i);function s(e){const t=a.useContext(o);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),a.createElement(o.Provider,{value:t},e.children)}}}]);